var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"와~ 바닐라 아이스크림도 남아 있고, 살 만한 세계네.","JPN":"おお～バニラアイスも残ってるし、なかなかステキな世界ですね。","ENG":"Wow, vanilla ice cream! This world is still livable!","TWN":"哇～竟然還有香草冰淇淋，這世界真值得住下來。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"다섯 살 이후로 못 먹어 봤는데.","JPN":"5歳以降、食べられなかったのに。","ENG":"I haven't eaten this since I was five.","TWN":"我從五歲之後就再也沒吃過了。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"군 보급품 특유의 공산품스러운 맛이 나긴 하지만......","JPN":"軍隊の補給品ならではの、人工的な味はしますけど……","ENG":"It has that plasticky aftertaste that all military rations have, but...","TWN":"雖然軍隊的補給品總有股工業製品的味道，不過……"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"음! 그래도 아주 달콤해!","JPN":"うん！　それでも、あま～い！","ENG":"Mm, mm! It's still yummy!","TWN":"嗯！還是很甜！"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"침식체들을 막으라고 보냈더니 혼자서 뭘 노닥거리고 있는 겁니까!","JPN":"侵食体への対抗を頼んだはずなのに、何を一人でのんびりしてるんですか！","ENG":"I sent you there to stop the C.O.s. What are you doing instead?","TWN":"我派妳去阻止侵蝕體，結果妳自己一個人在那邊嗨什麼！"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"걱정 마세요. 방어선은 확실하게 지키고 있답니다.","JPN":"心配無用ですよ。防御線はかたく守っていますから。","ENG":"Don't worry. I haven't forgotten about our defense line here.","TWN":"請不要擔心。我有好好守著防線喔。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"카린 양은 에어컨 바람 쐬는 동안 저는 땡볕 아래서 고생하는데, 아이스크림 정도는 괜찮잖아요?","JPN":"カリンさんがエアコンの風にあたっている間、私は炎天下で苦労してるんですから、アイスくらい別にいいじゃないですか？","ENG":"I'm out in the sun sweating while you're indoors enjoying cool, air-conditioned air. I thought I could eat some ice cream.","TWN":"而且卡琳小姐自己吹著冷氣，我卻頂著烈日在工作，吃個冰淇淋不過分吧？"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"아, 혹시 혼자 먹어서 삐졌어요? 한 통 갖다 드릴까요?","JPN":"あ、もしかして、私が一人で食べてて拗ねちゃったとか？　一個、あげましょうか？","ENG":"Oh, are you upset because I'm eating it alone? Want me to get you a carton?","TWN":"啊，還是因為就我有冰淇淋吃妳不高興了？要我幫妳帶一個過去嗎？"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"필요 없습니다!","JPN":"いりません！","ENG":"No, thank you!","TWN":"不需要！"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그보다 이제부터 차원 통로 연결을 시작할 겁니다.","JPN":"それより、これから次元間通路への接続を開始します。","ENG":"By the way, I'm going to establish a dimensional passage from now on.","TWN":"現在馬上就要開始連接次元通道了。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"도중에 침식체들이 난입했다간 파장이 흐트러져서 임무가 실패로 돌아갈 수 있어요.","JPN":"途中で侵食体たちに乱入されたら、波長が乱れて任務が失敗に終わるかもしれません。","ENG":"And I can't have C.O.s interfering with the frequency, or our mission will fail.","TWN":"如果途中有侵蝕體入侵，有可能會擾亂波長，導致任務失敗。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"이제 더 이상의 다이브는 우리 힘으로 불가능해요.","JPN":"これ以上のダイブは、私たちの力では不可能です。","ENG":"We can't dive any deeper on our own.","TWN":"現在憑我們的力量無法再進行躍入。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"억지로 시도했다간 둘 다 차원의 미아가 되고, 임무는 중단되어 버리겠죠.","JPN":"強引に進めたら、二人とも次元の間で迷子になり、任務は中止になるでしょうね。","ENG":"If we force it, we will get lost in some unknown dimension before we accomplish our mission.","TWN":"如果強行嘗試躍入，我們兩個都會迷失在次元中，任務就終止了。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그러니까...... 그러니까 여기서......","JPN":"ですから……ですから、ここで……","ENG":"So... So, we must...","TWN":"所以……所以這裡……"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"......여기서, 반드시 끝을 내야 해요.","JPN":"……ここで、必ず決着をつけないと。","ENG":"We must finish it right here and now.","TWN":"……我們必須結束它。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그러니까 아이스크림 따위에 정신 팔지 말고 방어선을 유지하는 데 집중하세요.","JPN":"だから、アイスなんかに気を取られてる場合じゃありません。防御線の維持に集中してください。","ENG":"So, forget the ice cream and focus on maintaining the defense line.","TWN":"所以請不要因為一個區區冰淇淋分心，專注維持防線。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"알겠습니까?","JPN":"いいですね？","ENG":"Get it?","TWN":"懂了嗎？"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};